import { useEffect, useMemo, useState } from "react";
import MetricCard from "../components/MetricCard";
import PageHeader from "../components/PageHeader";
import { getAppointments, getAssessment, getMedications, getProfile, getReports, listInsuranceRequests } from "../services/api";

export default function UserDashboardPage() {
  const [profile, setProfile] = useState(null);
  const [assessment, setAssessment] = useState(null);
  const [appointments, setAppointments] = useState([]);
  const [medications, setMedications] = useState([]);
  const [reports, setReports] = useState([]);
  const [insurance, setInsurance] = useState([]);

  useEffect(() => {
    const load = async () => {
      const [profileData, assessmentData, appointmentsData, medicationsData, reportsData, insuranceData] = await Promise.all([
        getProfile(),
        getAssessment(),
        getAppointments(),
        getMedications(),
        getReports(),
        listInsuranceRequests(),
      ]);
      setProfile(profileData);
      setAssessment(assessmentData);
      setAppointments(appointmentsData);
      setMedications(medicationsData);
      setReports(reportsData);
      setInsurance(insuranceData);
    };
    load();
  }, []);

  const recentItems = useMemo(() => appointments.slice(0, 3), [appointments]);

  return (
    <>
      <PageHeader
        title="Dashboard Overview"
        description="A clean summary of your health activity, recent progress, and quick routes into each module."
      />
      <div className="card-grid">
        <MetricCard label="Assessment" value={profile?.first_login_completed ? "Completed" : "Pending"} />
        <MetricCard label="Appointments" value={appointments.length} />
        <MetricCard label="Active Medications" value={medications.length} />
        <MetricCard label="Reports Stored" value={reports.length} />
      </div>
      <div className="split-layout">
        <div className="panel">
          <h3 className="section-title">Recent Activity</h3>
          <div className="summary-list">
            {recentItems.length ? recentItems.map((item) => (
              <div key={item.id} className="summary-item">
                <strong>{item.hospital_name}</strong>
                <div>{item.appointment_date} at {item.appointment_time}</div>
                <span className="pill">{item.status}</span>
              </div>
            )) : <p className="muted">No recent appointments yet.</p>}
          </div>
        </div>
        <div className="panel">
          <h3 className="section-title">Alerts and Guidance</h3>
          <div className="summary-list">
            <div className="summary-item">
              <strong>Assessment Summary</strong>
              <div>{assessment?.summary || "Complete your first assessment to unlock personalized guidance."}</div>
            </div>
            <div className="summary-item">
              <strong>Insurance Requests</strong>
              <div>{insurance.length} request(s) submitted for review.</div>
            </div>
            <div className="summary-item">
              <strong>Quick Tip</strong>
              <div>Use the AI Assistant from any page to navigate modules and pre-fill requests.</div>
            </div>
          </div>
        </div>
      </div>
      <div className="panel" style={{ marginTop: 18 }}>
        <h3 className="section-title">Quick Shortcuts</h3>
        <div className="shortcut-grid">
          <a className="shortcut-card" href="/symptoms">Check Symptoms</a>
          <a className="shortcut-card" href="/appointments">Book Appointment</a>
          <a className="shortcut-card" href="/medications">Manage Medication</a>
          <a className="shortcut-card" href="/reports">Scan Reports</a>
          <a className="shortcut-card" href="/insurance">Insurance Help</a>
          <a className="shortcut-card" href="/assistant">Open AI Assistant</a>
        </div>
      </div>
    </>
  );
}
